from pydantic import BaseModel, Field
from typing import List, Optional
import anthropic

client = anthropic.Anthropic()

class JobListing(BaseModel):
    title: str = Field(description='Job title')
    company: str = Field(description='Company name')
    location: Optional[str] = Field(None, description='City or remote')
    salary_range: Optional[str] = Field(None, description='Salary range if stated')
    required_skills: List[str] = Field(default_factory=list)
    experience_years: Optional[int] = Field(None, description='Minimum years required')

def extract_job_listings(page_text: str) -> List[JobListing]:
    'Extract all job listings from the given page text.'
    tool = {
        'name': 'save_job_listings',
        'description': 'Save a list of extracted job listings.',
        'input_schema': {
            'type': 'object',
            'properties': {
                'listings': {
                    'type': 'array',
                    'items': JobListing.model_json_schema(),
                },
            },
            'required': ['listings'],
        },
    }
    response = client.messages.create(
        model='claude-opus-4-5',
        max_tokens=2048,
        tools=[tool],
        tool_choice={'type': 'tool', 'name': 'save_job_listings'},
        messages=[{
            'role': 'user',
            'content': (
                'Extract all job listings from the text below. '
                'Use null for fields that cannot be determined.

'
                + page_text[:4000]
            ),
        }],
    )
    tool_block = next(b for b in response.content if b.type == 'tool_use')
    raw_listings = tool_block.input.get('listings', [])
    return [JobListing(**item) for item in raw_listings]

# Usage
page_content = 'Senior Python Engineer at Acme Corp in San Francisco, 40k-80k, 5+ years Python, FastAPI, AWS required...'
jobs = extract_job_listings(page_content)
for job in jobs:
    print(job.model_dump_json(indent=2))
